import anthropic


def classify_failure(
    exc: Exception,
    tool_name: Optional[str] = None,
    tool_input: Optional[dict] = None,
) -> FailureReport:
    raw = repr(exc)

    if isinstance(exc, anthropic.APIStatusError):
        status = exc.status_code
        if status == 429:
            return FailureReport(
                category=FailureCategory.LLM_ERROR,
                severity=Severity.RECOVERABLE,
                message=f"Rate limit (429): {exc.message}",
                raw_exception=raw,
            )
        if status >= 500:
            return FailureReport(
                category=FailureCategory.LLM_ERROR,
                severity=Severity.RECOVERABLE,
                message=f"Server error ({status})",
                raw_exception=raw,
            )
        # 400 context overflow
        if "context" in str(exc).lower() or "token" in str(exc).lower():
            return FailureReport(
                category=FailureCategory.LLM_ERROR,
                severity=Severity.FATAL,
                message="Context window overflow",
                raw_exception=raw,
            )
        return FailureReport(
            category=FailureCategory.LLM_ERROR,
            severity=Severity.FATAL,
            message=f"API client error ({status})",
            raw_exception=raw,
        )

    if isinstance(exc, (TimeoutError, ConnectionError, OSError)):
        return FailureReport(
            category=FailureCategory.TOOL_ERROR,
            severity=Severity.RECOVERABLE,
            message=f"Network failure calling {tool_name or 'unknown'}",
            tool_name=tool_name,
            tool_input=tool_input,
            raw_exception=raw,
        )

    if tool_name:
        return FailureReport(
            category=FailureCategory.TOOL_ERROR,
            severity=Severity.RECOVERABLE,
            message=f"Tool {tool_name!r} raised {type(exc).__name__}",
            tool_name=tool_name,
            tool_input=tool_input,
            raw_exception=raw,
        )

    return FailureReport(
        category=FailureCategory.LLM_ERROR,
        severity=Severity.FATAL,
        message=f"Unexpected exception: {type(exc).__name__}",
        raw_exception=raw,
    )

from dataclasses import dataclass
from typing import List


@dataclass
class ToolCall:
    name: str
    input: dict


def detect_loop(
    history: List[ToolCall],
    repeat_threshold: int = 3,
) -> Optional[FailureReport]:
    """Return a FailureReport if the last N tool calls are identical."""
    if len(history) < repeat_threshold:
        return None
    tail = history[-repeat_threshold:]
    first_name = tail[0].name
    first_input = tail[0].input
    if all(c.name == first_name and c.input == first_input for c in tail):
        return FailureReport(
            category=FailureCategory.LOGIC_ERROR,
            severity=Severity.FATAL,
            message=(
                f"Infinite loop detected: {first_name!r} called "
                f"{repeat_threshold} times with identical inputs"
            ),
            tool_name=first_name,
            tool_input=first_input,
        )
    return None


def detect_tool_count_exceeded(
    history: List[ToolCall],
    max_calls: int = 25,
) -> Optional[FailureReport]:
    if len(history) >= max_calls:
        return FailureReport(
            category=FailureCategory.LOGIC_ERROR,
            severity=Severity.FATAL,
            message=f"Tool call limit reached ({max_calls})",
            context={"total_calls": len(history)},
        )
    return None

UNCERTAINTY_PHRASES = [
    "i don't know",
    "i cannot",
    "i'm not sure",
    "i am unable",
    "as an ai",
]


def validate_output(
    output: str,
    min_length: int = 50,
    required_fields: Optional[List[str]] = None,
) -> Optional[FailureReport]:
    if not output or len(output.strip()) < min_length:
        return FailureReport(
            category=FailureCategory.SILENT_FAILURE,
            severity=Severity.DEGRADED,
            message=(
                f"Output too short: {len(output.strip())} chars "
                f"(minimum {min_length})"
            ),
            context={"output_preview": output[:100]},
        )

    lower = output.lower()
    for phrase in UNCERTAINTY_PHRASES:
        if phrase in lower:
            return FailureReport(
                category=FailureCategory.SILENT_FAILURE,
                severity=Severity.DEGRADED,
                message=f"Output contains refusal/uncertainty phrase: {phrase!r}",
                context={"output_preview": output[:200]},
            )

    if required_fields:
        missing = [f for f in required_fields if f not in output]
        if missing:
            return FailureReport(
                category=FailureCategory.SILENT_FAILURE,
                severity=Severity.DEGRADED,
                message=f"Output missing required fields: {missing}",
            )

    return None

import anthropic
import time


class AgentResult:
    def __init__(self, output: str, failures: List[FailureReport]):
        self.output = output
        self.failures = failures
        self.ok = not any(f.severity == Severity.FATAL for f in failures)


def run_agent_with_analysis(
    client: anthropic.Anthropic,
    messages: list,
    tools: list,
    system: str = "",
    max_retries: int = 3,
    max_tool_calls: int = 25,
    min_output_length: int = 50,
) -> AgentResult:
    failures: List[FailureReport] = []
    tool_history: List[ToolCall] = []
    retry_delay = 2.0

    for attempt in range(max_retries + 1):
        try:
            response = client.messages.create(
                model="claude-haiku-4-5-20251001",
                max_tokens=4096,
                system=system,
                messages=messages,
                tools=tools,
            )
        except Exception as exc:
            report = classify_failure(exc)
            failures.append(report)
            if not report.is_retryable() or attempt == max_retries:
                return AgentResult("", failures)
            time.sleep(retry_delay)
            retry_delay *= 2
            continue

        if response.stop_reason == "end_turn":
            output = next(
                (b.text for b in response.content if hasattr(b, "text")), ""
            )
            silent = validate_output(output, min_length=min_output_length)
            if silent:
                failures.append(silent)
            return AgentResult(output, failures)

        if response.stop_reason == "tool_use":
            tool_blocks = [b for b in response.content if b.type == "tool_use"]
            tool_results = []

            for block in tool_blocks:
                tool_history.append(ToolCall(name=block.name, input=block.input))

                # logic checks after each tool call
                loop_report = detect_loop(tool_history)
                if loop_report:
                    failures.append(loop_report)
                    return AgentResult("", failures)

                count_report = detect_tool_count_exceeded(tool_history, max_tool_calls)
                if count_report:
                    failures.append(count_report)
                    return AgentResult("", failures)

                # dispatch tool (placeholder -- wire to your tool registry)
                try:
                    result = dispatch_tool(block.name, block.input)
                except Exception as exc:
                    report = classify_failure(exc, tool_name=block.name,
                                             tool_input=block.input)
                    failures.append(report)
                    if not report.is_retryable():
                        return AgentResult("", failures)
                    result = f"Error: {exc}"

                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": str(result),
                })

            messages = messages + [
                {"role": "assistant", "content": response.content},
                {"role": "user", "content": tool_results},
            ]

    return AgentResult("", failures)

from collections import Counter, defaultdict
from typing import List


class FailureAggregator:
    def __init__(self):
        self._reports: List[FailureReport] = []

    def record(self, result: AgentResult) -> None:
        self._reports.extend(result.failures)

    def summary(self) -> dict:
        total = len(self._reports)
        by_category = Counter(r.category.value for r in self._reports)
        by_severity = Counter(r.severity.value for r in self._reports)
        tool_errors: dict = defaultdict(int)
        for r in self._reports:
            if r.tool_name:
                tool_errors[r.tool_name] += 1
        return {
            "total_failures": total,
            "by_category": dict(by_category),
            "by_severity": dict(by_severity),
            "tool_error_counts": dict(tool_errors),
        }

    def print_summary(self) -> None:
        s = self.summary()
        print(f"Total failures: {s['total_failures']}")
        print("By category:")
        for cat, n in sorted(s["by_category"].items(), key=lambda x: -x[1]):
            print(f"  {cat}: {n}")
        print("By severity:")
        for sev, n in sorted(s["by_severity"].items(), key=lambda x: -x[1]):
            print(f"  {sev}: {n}")
        if s["tool_error_counts"]:
            print("Tool errors:")
            for tool, n in sorted(s["tool_error_counts"].items(), key=lambda x: -x[1]):
                print(f"  {tool}: {n}")


# Usage
aggregator = FailureAggregator()
for task in tasks:
    result = run_agent_with_analysis(client, task.messages, tools)
    aggregator.record(result)

aggregator.print_summary()

import json


def validate_search_result(raw: str) -> tuple[str, Optional[FailureReport]]:
    """Validate a JSON search result from a tool call."""
    try:
        data = json.loads(raw)
    except json.JSONDecodeError as exc:
        return raw, FailureReport(
            category=FailureCategory.TOOL_ERROR,
            severity=Severity.RECOVERABLE,
            message=f"Tool returned invalid JSON: {exc}",
            context={"raw_preview": raw[:200]},
        )

    if not isinstance(data, dict) or "results" not in data:
        return raw, FailureReport(
            category=FailureCategory.TOOL_ERROR,
            severity=Severity.DEGRADED,
            message="Tool response missing 'results' key",
        )

    if not data["results"]:
        return raw, FailureReport(
            category=FailureCategory.SILENT_FAILURE,
            severity=Severity.DEGRADED,
            message="Search returned zero results",
        )

    return raw, None  # valid


# In the agent loop, after dispatching a tool:
raw_result = dispatch_tool(block.name, block.input)
if block.name == "web_search":
    raw_result, validation_report = validate_search_result(str(raw_result))
    if validation_report:
        failures.append(validation_report)

import json
import time


def save_post_mortem(
    result: AgentResult,
    tool_history: List[ToolCall],
    path: str,
) -> None:
    data = {
        "output": result.output,
        "ok": result.ok,
        "failures": [
            {
                "category": r.category.value,
                "severity": r.severity.value,
                "message": r.message,
                "timestamp": r.timestamp,
                "tool_name": r.tool_name,
                "tool_input": r.tool_input,
                "raw_exception": r.raw_exception,
                "context": r.context,
            }
            for r in result.failures
        ],
        "tool_history": [
            {"name": c.name, "input": c.input}
            for c in tool_history
        ],
    }
    with open(path, "w") as f:
        json.dump(data, f, indent=2)


# Usage: save on any fatal failure
if not result.ok:
    save_post_mortem(result, tool_history, f"postmortem_{int(time.time())}.json")
